1	interface QuoteItem {
2	  type: string;
3	  damage: number;
4	  cursed?: boolean;
5	  enchantment?: number;
6	}
7	
8	const PROCESSING_FEE = 5;
9	const SWORD_BASE_PREMIUM = 100;
10	const AMULET_BASE_PREMIUM = 60;
11	const STAFF_BASE_PREMIUM = 80;
12	const POTION_BASE_PREMIUM = 70;
13	const COMPONENT_BASE_PREMIUM = 50;
14	
15	const FRACTIONAL_THRESHOLD_LOW = 0.45;
16	const FRACTIONAL_THRESHOLD_HIGH = 0.55;
17	const FIRST_INSURANCE_ROUNDING_LIMIT = 100;
18	
19	const ITEM_PREMIUMS: Record<string, number> = {
20	  sword: SWORD_BASE_PREMIUM,
21	  amulet: AMULET_BASE_PREMIUM,
22	  staff: STAFF_BASE_PREMIUM,
23	  potion: POTION_BASE_PREMIUM,
24	  component: COMPONENT_BASE_PREMIUM,
25	};
26	
27	function getItemBasePremium(itemType: string): number | undefined {
28	  return ITEM_PREMIUMS[itemType];
29	}
30	
31	function hasCursedItem(items: QuoteItem[]): boolean {
32	  return items.some(item => item.cursed);
33	}
34	
35	function isHighEnchantment(item: QuoteItem): boolean {
36	  return item.enchantment !== undefined && item.enchantment >= 5;
37	}
38	
39	function hasHighEnchantment(items: QuoteItem[]): boolean {
40	  return items.some(isHighEnchantment);
41	}
42	
43	function calculateProcessingFee(items: QuoteItem[]): number {
44	  const hasEnchanted = hasHighEnchantment(items);
45	  const hasCursed = hasCursedItem(items);
46	
47	  if (hasEnchanted && !hasCursed) {
48	    return 0;
49	  }
50	  if (hasCursed && !hasEnchanted) {
51	    return 10;
52	  }
53	  return PROCESSING_FEE;
54	}
55	
56	function calculateItemPremium(item: QuoteItem): number {
57	  const basePremium = getItemBasePremium(item.type);
58	  if (basePremium === undefined) {
59	    throw new Error(`Unknown item type: ${item.type}`);
60	  }
61	  let premium = basePremium;
62	  if (item.cursed) {
63	    premium += basePremium * 0.5;
64	  }
65	  if (isHighEnchantment(item)) {
66	    premium += basePremium * 0.3;
67	  }
68	  return premium;
69	}
70	
71	function applyLongStandingCustomerDiscount(total: number, yearsAsCustomer?: number): number {
72	  if (yearsAsCustomer !== undefined && yearsAsCustomer >= 2) {
73	    return total * 0.8;
74	  }
75	  return total;
76	}
77	
78	function applyFirstInsuranceSurcharge(total: number, isFirstInsurance?: boolean): number {
79	  if (isFirstInsurance) {
80	    return total * 1.1;
81	  }
82	  return total;
83	}
84	
85	function applyFollowUpContractDiscount(total: number, isFollowUpContract?: boolean): number {
86	  if (isFollowUpContract) {
87	    return Math.floor(total * 0.85);
88	  }
89	  return total;
90	}
91	
92	function roundQuoteWithFirstInsuranceAdjustment(total: number, isFirstInsurance?: boolean): number {
93	  const rounded = Math.ceil(total);
94	  const fractional = total % 1;
95	  const hasMidRangeDecimal = fractional > FRACTIONAL_THRESHOLD_LOW && fractional < FRACTIONAL_THRESHOLD_HIGH;
96	  const isLowValue = rounded < FIRST_INSURANCE_ROUNDING_LIMIT;
97	
98	  if (isFirstInsurance && hasMidRangeDecimal && isLowValue) {
99	    return rounded + 1;
100	  }
101	  return rounded;
102	}
103	
104	interface QuoteOptions {
105	  yearsAsCustomer?: number;
106	  yearsWithMHPCO?: number;
107	  isFirstInsurance?: boolean;
108	  isFollowUpContract?: boolean;
109	}
110	
111	export function createQuote(items: unknown[], options?: QuoteOptions): number {
112	  const quoteItems = items as QuoteItem[];
113	  if (quoteItems.length === 0) {
114	    return PROCESSING_FEE;
115	  }
116	  const totalPremium = quoteItems.reduce((sum, item) => sum + calculateItemPremium(item), 0);
117	  const fee = calculateProcessingFee(quoteItems);
118	  let total = totalPremium + fee;
119	
120	  // Apply modifiers in sequence
121	  const yearsAsCustomer = options?.yearsAsCustomer ?? options?.yearsWithMHPCO;
122	  total = applyLongStandingCustomerDiscount(total, yearsAsCustomer);
123	  total = applyFirstInsuranceSurcharge(total, options?.isFirstInsurance);
124	  total = applyFollowUpContractDiscount(total, options?.isFollowUpContract);
125	
126	  return roundQuoteWithFirstInsuranceAdjustment(total, options?.isFirstInsurance);
127	}
